using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x = 0, f = 1;
		char ch = gc();
		wh(ch < '0' || ch > '9')
		{
			if (ch == '-')f = -1;
			ch = getchar();
		}
		wh(ch >= '0' && ch <= '9')
		{
			x = x * 10 + ch - '0';
			ch = gc();
		}
		return x * f;
	}
	void write(ll x)
	{
		if (x < 0)pc('-'), x = -x;
		if (x > 9)write(x / 10);
		pc(x % 10 + '0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
CI N=1010;
string op[N], ad[N], s[N][30];
char ch[30];
int n;
bool mx_ (string x, string y)
{
	return x.size() > y.size() || x.size() == y.size() && x > y;
}
bool notzero (string x)
{
	return x.size() == 1 || x.size() > 1 && x[0] != '0';
}
void solve (int x)
{
	int k = 0;
	for (int i = 0; ad[x][i]; i++)
	{
		if (!isdigit (ad[x][i]))
		{
			ch[++k] = ad[x][i];
		}
		else s[x][k] += ad[x][i];
	}
	if (!(ch[1] == '.' && ch[2] == '.' && ch[3] == '.' && ch[4] == ':' && k == 4 && !(mx_ (s[x][0], "255") || mx_ (s[x][1], "255") || mx_ (s[x][2], "255") || mx_ (s[x][3], "255") || mx_ (s[x][4], "65535")) && notzero (s[x][0]) && notzero (s[x][1]) && notzero (s[x][2]) && notzero (s[x][3]) && notzero (s[x][4])))
	{
		cout << "ERR\n";
		return ;
	}
	if (op[x] == "Server")
	{
		bool fl = 1;
		FOR(i,1,x-1)
		{
			if (op[i] == "Server" && ad[i] == ad[x])
			{
				cout << "FAIL\n";
				fl = 0;
				break;
			}
		}
		if (fl)
		{
			cout << "OK\n";
		}
	}
	else
	{
		bool fl = 1;
		FOR(i,1,x-1)
		{
			if (op[i] == "Server" && ad[i] == ad[x])
			{
				cout << i << "\n";
				fl = 0;
				break;
			}
		}
		if (fl)
		{
			cout << "FAIL\n";
		}
	}
}
signed main(void)
{
	cin >> n;
	FOR(i,1,n)
	{
		cin >> op[i] >> ad[i];
		solve (i);
	}
	return false;
}
